"""
MKT Original Language Commentary — Romans chapters 4–7
Run: python3 scripts/zc-original-romans-4-7.py

Source data used:
- data/interlinear/romans.json
- data/translation/glossary-greek.json (logizomai, pistis, sarx, nomos)
- data/translation/draft/mediating/romans.json (MKT text for ch4-7)

Key philological decisions:
- 4:3 elogisthē (aorist passive) — the reckoning is a single divine act, not an ongoing assessment
- 4:5 ton asebē (the ungodly) — God justifies precisely the ungodly; this is Paul's scandal
- 5:1 eirēnēn echomen vs. schōmen — the indicative/subjunctive textual variant;
  MKT follows the majority text with indicative (we have peace, not let us have peace)
- 5:12 eph' hō — interpreted as causal "because" (not "in whom");
  all sinned individually (not merely in Adam representatively) though the Adamic transmission is real
- 6:5 symphytoi — the "grown-together-with" image implies organic union, not mere moral imitation
- 7:14 "wretched man" passage — intentionally left as a live debate (Christian/pre-Christian);
  the MKT notes both readings; the present-tense I-language is the strongest signal for Christian
- 7:24 tis me rhysetai — future tense; a rescue still expected
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ROMANS = {
  "4": {
    "1": '<p><strong>τὸν προπάτορα ἡμῶν κατὰ σάρκα</strong> (<em>ton propatora hēmōn kata sarka</em>) — "our forefather according to the flesh." The <em>kata sarka</em> qualification anticipates Paul\'s argument: Abraham is relevant as forefather according to the flesh only as a starting point; his real significance is as father of faith (vv11-12). The shift from fleshly descent to faith-descent is the letter\'s central move for defining who belongs to the people of God.</p>',
    "2": '<p><strong>ἔχει καύχημα ἀλλ᾽ οὐ πρὸς θεόν</strong> (<em>echei kauchēma all\' ou pros theon</em>) — "he has a boast, but not before God." <em>Kauchēma</em> (boast, ground of pride) — Paul grants the hypothetical: if Abraham were justified by works, he would have a legitimate ground of pride before other humans. But the divine court operates differently; what impresses human evaluators does not constitute righteousness before God, whose standard is being-without-boast (3:27).</p>',
    "3": '<p><strong>ἐλογίσθη αὐτῷ εἰς δικαιοσύνην</strong> (<em>elogisthē autō eis dikaiosynēn</em>) — "it was credited to him as righteousness." The aorist passive of <em>logizomai</em>: a single completed act of divine reckoning. The subject is "faith" (Abraham\'s trust in God\'s promise); the object reckoned is "righteousness" — the standing before God that the faith-act receives as its divine valuation. The verb will be repeated eight times in ch4, building a sustained argument from the single Genesis text (Gen 15:6).</p>',
    "4": '<p><strong>τὸ μισθὸς οὐ λογίζεται κατὰ χάριν ἀλλὰ κατὰ ὀφείλημα</strong> (<em>to misthos ou logizetai kata charin alla kata opheilēma</em>) — "the wage is not credited according to grace but according to what is owed." <em>Opheilēma</em> (debt, what is owed) — the wage-worker analogy establishes the contrast: wages are debt-obligations, not gifts. If justification were by works, God would be the debtor; but God is no one\'s debtor, making justification-by-works a category error about the nature of the divine-human relationship.</p>',
    "5": '<p><strong>τῷ δὲ μὴ ἐργαζομένῳ πιστεύοντι δὲ ἐπὶ τὸν δικαιοῦντα τὸν ἀσεβῆ</strong> (<em>tō de mē ergazomenō pisteuonti de epi ton dikaiounta ton asebē</em>) — "but to the one who does not work but believes in the one who justifies the ungodly." <em>Ton asebē</em> (the ungodly one) is the stunning element: God justifies the <em>ungodly</em>, not the merely-imperfect or the almost-righteous. The one who has no works to offer is precisely the candidate for grace-reckoning. Paul\'s description of God as "the one who justifies the ungodly" directly inverts Exod 23:7 ("do not acquit the guilty").</p>',
    "6": '<p><strong>μακαρισμὸν</strong> (<em>makarismon</em>) — "blessedness," the state of being blessed — the same root as the Beatitudes (<em>makarios</em>). David\'s declaration of blessedness in Ps 32:1-2 becomes Paul\'s second OT witness (after Gen 15:6) that right-standing before God is received, not earned. The Psalter\'s own voice confirms the Genesis principle.</p>',
    "7": '<p><strong>ἀφέθησαν... ἐπεκαλύφθησαν</strong> (<em>aphethēsan... epekaluphthēsan</em>) — "have been forgiven... have been covered" — both aorist passives; the divine act of forgiveness is completed and stands. <em>Aphiēmi</em> (to send away, release) and <em>epikaryptō</em> (to cover over) are two images for the same reality: the debt is cancelled and the evidence is hidden. LXX Ps 32:1 uses these verbs; Paul imports them verbatim.</p>',
    "8": '<p><strong>οὗ οὐ μὴ λογίσηται κύριος ἁμαρτίαν</strong> (<em>hou ou mē logisētai kyrios hamartian</em>) — "to whom the Lord will never reckon sin" — the double negative <em>ou mē</em> with the subjunctive is emphatic negation: under no circumstances, not ever. The future subjunctive extends the non-reckoning into perpetuity. The same reckoning-verb that credits righteousness positively here refuses to credit sin negatively — both sides of the forensic ledger are covered by grace.</p>',
    "9": '<p><strong>ἐν περιτομῇ ὄντι ἢ καὶ ἐν ἀκροβυστίᾳ</strong> (<em>en peritomē onti ē kai en akrobystia</em>) — "to the circumcised or also to the uncircumcised?" Paul now asks when Abraham received the blessing — before or after circumcision. The temporal argument from Genesis: Gen 15:6 (faith credited) precedes Gen 17 (circumcision instituted) by approximately 14 years, making Abraham\'s justification happen in uncircumcision.</p>',
    "10": '<p><strong>οὐκ ἐν περιτομῇ ἀλλ᾽ ἐν ἀκροβυστίᾳ</strong> — "not in circumcision but in uncircumcision" — the historical sequence is Paul\'s argument: the faith-reckoning happened when Abraham was still an uncircumcised Gentile. The implication is that faith-righteousness is structurally prior to covenant-rite, making it available to all who believe regardless of circumcision-status.</p>',
    "11": '<p><strong>σφραγῖδα τῆς δικαιοσύνης τῆς πίστεως</strong> (<em>sphragida tēs dikaiosynēs tēs pisteōs</em>) — "a seal of the righteousness of the faith" — <em>sphragis</em> (seal) is the authentication mark that certifies a document\'s validity. Circumcision is the external seal that certifies the prior righteousness-by-faith; it does not produce the righteousness but certifies its existence. This makes circumcision meaningful but non-essential for the righteousness itself.</p>',
    "12": '<p><strong>τοῖς στοιχοῦσιν τοῖς ἴχνεσιν τῆς ἐν ἀκροβυστίᾳ πίστεως</strong> (<em>tois stoichousin tois ichnesin tēs en akrobystia pisteōs</em>) — "who follow in the footsteps of the faith that our father Abraham had while still uncircumcised." <em>Stoicheō</em> (to march in line, follow in order) + <em>ichnesin</em> (footprints, tracks) — a vivid image of following someone\'s literal footsteps. Those who retrace Abraham\'s faith-path (not his circumcision-path) become his offspring.</p>',
    "13": '<p><strong>κληρονόμον αὐτὸν εἶναι κόσμου</strong> (<em>klēronomon auton einai kosmou</em>) — "that he would be heir of the world" — <em>klēronomos</em> (heir, one who receives the inheritance by lot) — the promise to Abraham (land, seed, blessing) is here universalized to "the world," which Paul reads as the eschatological new-creation inheritance. The local promise to Canaan becomes the cosmic promise of the new earth; Paul reads Genesis through the lens of the prophets who expanded the Abrahamic promise to universal scope.</p>',
    "14": '<p><strong>εἰ γὰρ οἱ ἐκ νόμου κληρονόμοι</strong> (<em>ei gar hoi ek nomou klēronomoi</em>) — "if those who are of the law are heirs" — the conditional hypothetical: if inheritance were through law-keeping, then faith would be emptied (<em>kekenōtai</em>, perfect passive — "has been emptied/rendered void") and the promise would be nullified (<em>katērgētai</em> — "rendered inoperative"). The law cannot be the mechanism of inheritance because it cannot do what it demands (3:19-20).</p>',
    "15": '<p><strong>ὁ γὰρ νόμος ὀργὴν κατεργάζεται</strong> (<em>ho gar nomos orgēn katergazetai</em>) — "for the law brings about wrath" — the present active: law\'s operation produces wrath because it defines the standard that condemns its own transgressors. <strong>οὗ δὲ οὐκ ἔστιν νόμος, οὐδὲ παράβασις</strong> — "where there is no law, there is no transgression either" — <em>parabasis</em> (deliberate stepping-past) requires a known boundary; without the law, moral failure is <em>hamartia</em> (missing the mark) but not <em>parabasis</em> (knowing violation).</p>',
    "16": '<p><strong>ἐκ πίστεως, ἵνα κατὰ χάριν</strong> (<em>ek pisteōs, hina kata charin</em>) — "from faith, so that according to grace" — the causal chain: faith-basis → grace-character → promise-security. The logic is: only a grace-based promise can be universally reliable, because performance-based promises fail when performance fails. <strong>βεβαίαν εἶναι τὴν ἐπαγγελίαν παντὶ τῷ σπέρματι</strong> — "that the promise might be secure to all the offspring" — <em>bebaios</em> (firm, guaranteed, bankable) — a commercial-legal term for a guaranteed transaction; the promise is reliable precisely because it depends on God\'s faithfulness, not human performance.</p>',
    "17": '<p><strong>τοῦ ζωοποιοῦντος τοὺς νεκροὺς καὶ καλοῦντος τὰ μὴ ὄντα ὡς ὄντα</strong> (<em>tou zōopoiountos tous nekrous kai kalountos ta mē onta hōs onta</em>) — "the one who gives life to the dead and calls things that are not as though they are." Two divine attributes grounding Abraham\'s faith: (1) <em>zōopoieō</em> (give life) — applicable both to Sarah\'s womb and to the resurrection; (2) the creative calling of non-being into being (<em>ta mē onta hōs onta</em>) — the language of <em>creatio ex nihilo</em>. The God Abraham trusted is the Creator and Resurrector simultaneously.</p>',
    "18": '<p><strong>παρ᾽ ἐλπίδα ἐπ᾽ ἐλπίδι</strong> (<em>par\' elpida ep\' elpidi</em>) — "against hope, in hope." The paradoxical phrase is precisely constructed: <em>par\' elpida</em> (contrary to visible/calculable expectation) and <em>ep\' elpidi</em> (grounded-on-hope = the divine promise). Abraham\'s faith is rational at the divine level while irrational at the human level; it trusts the God who makes promises rather than the circumstances that deny their possibility.</p>',
    "19": '<p><strong>μὴ ἀσθενήσας τῇ πίστει</strong> (<em>mē asthenēsas tē pistei</em>) — "not weakening in faith" — the aorist participle: he did not at the decisive moment collapse in unbelief. <strong>κατενόησεν τὸ ἑαυτοῦ σῶμα ἤδη νενεκρωμένον</strong> (<em>katenovēsen to heautou sōma ēdē nenekrōmenon</em>) — "he considered his own body, already deadened" — <em>nenekrōmenon</em>: perfect passive participle of <em>nekroō</em> (to put to death, make corpse-like). Abraham saw the biological reality clearly; his faith was not blind optimism but clear-eyed trust in the promise-maker.</p>',
    "20": '<p><strong>εἰς δὲ τὴν ἐπαγγελίαν τοῦ θεοῦ οὐ διεκρίθη τῇ ἀπιστίᾳ ἀλλ᾽ ἐνεδυναμώθη τῇ πίστει</strong> — "but regarding the promise of God he did not waver in unbelief but was strengthened in faith." <em>Diakrinomai</em> (to be divided, waver, doubt) — the passive implies an external force that Abraham did not yield to. <em>Enedynamoō</em> (to be empowered, strengthened) — the passive equally implies a divine empowerment; faith itself is a gift that enables trust in the promise. <strong>δοὺς δόξαν τῷ θεῷ</strong> — "giving glory to God" — glory-giving through faith rather than through performance is Paul\'s definition of true worship.</p>',
    "21": '<p><strong>πεπληροφορημένος</strong> (<em>peplērophorēmenos</em>) — perfect passive participle of <em>plērophoreō</em> (to be fully persuaded, carried to fullness of conviction). The completeness of Abraham\'s persuasion is emphasized by the <em>plēro-</em> prefix and the perfect tense: he arrived at and remained in full conviction. The object: the divine ability to do what he promised (<em>ποιῆσαι, hoper epēngeltai, dynatos ēstin</em>).</p>',
    "22": '<p><strong>διὸ καὶ ἐλογίσθη αὐτῷ εἰς δικαιοσύνην</strong> — "therefore it was also credited to him as righteousness" — the <em>dio kai</em> (therefore also) marks the logical consequence: the faith just described in vv17-21 is the faith that Gen 15:6 credits as righteousness. Paul\'s description of Abraham\'s faith is a theological unpacking of the Genesis statement, not a separate claim.</p>',
    "23": '<p><strong>οὐκ ἐγράφη δὲ δι᾽ αὐτὸν μόνον</strong> (<em>ouk egraphē de di\' auton monon</em>) — "but it was not written for his sake only" — the passive <em>egraphē</em> (it was written) is a divine passive: God wrote the Scripture for all its future readers, not merely as a record of Abraham\'s biography. The hermeneutical principle: OT narrative has a prospective, not merely retrospective, function.</p>',
    "24": '<p><strong>τοῖς πιστεύουσιν ἐπὶ τὸν ἐγείραντα Ἰησοῦν τὸν κύριον ἡμῶν ἐκ νεκρῶν</strong> — "for those who believe in the one who raised Jesus our Lord from the dead." The resurrection of Christ is the definitive divine act that constitutes the content of the present-day faith that receives the same reckoning Abraham received. Believing in the resurrection-God is the NT form of Abraham\'s believing in the promise-God.</p>',
    "25": '<p><strong>παρεδόθη διὰ τὰ παραπτώματα ἡμῶν καὶ ἠγέρθη διὰ τὴν δικαίωσιν ἡμῶν</strong> — "he was handed over on account of our trespasses and raised on account of our justification." The chiasm (death → trespasses; resurrection → justification) pairs the two events with their respective grounds. <em>Egēgertai</em> in other contexts would be perfect (4:25 uses aorist here: <em>ēgerthē</em>); the aorist marks the historical event. <em>Dia</em> with accusative can mean "on account of/for the sake of" or "because of": both meanings are simultaneously true — Christ raised because justification is accomplished and in order that justification is applied.</p>'
  },
  "5": {
    "1": '<p><strong>εἰρήνην ἔχομεν πρὸς τὸν θεόν</strong> (<em>eirēnēn echomen pros ton theon</em>) — "we have peace with God." The indicative <em>echomen</em> (we have) versus the subjunctive <em>schōmen</em> (let us have) is one of the most debated textual variants in the NT. External evidence slightly favors the subjunctive (Codices Sinaiticus, Vaticanus, Alexandrinus), but the indicative makes better logical sense in context: Paul has just argued for justification by faith and now states its consequences. <em>Eirēnē</em> here is the OT shalom — not merely absence of conflict but positive relational wholeness with God.</p>',
    "2": '<p><strong>τὴν προσαγωγὴν ἐσχήκαμεν</strong> (<em>tēn prosagōgēn eschēkamen</em>) — "we have gained access" — perfect active of <em>echō</em>: a past gaining with continuing possession. <em>Prosagōgē</em> (access, approach) is a technical term from the royal court: the formal introduction that grants audience with the king; or from the temple: the approach to the divine presence. Through Christ the believer has been formally introduced into the divine presence and maintains ongoing access.</p><p><strong>ἐν ᾗ ἑστήκαμεν</strong> (<em>en hē hestēkamen</em>) — "in which we stand" — perfect active of <em>histēmi</em>: having taken a position and remaining in it. Grace is not merely the door through which one passes but the sphere in which one permanently stands.</p>',
    "3": '<p><strong>καυχώμεθα ἐν ταῖς θλίψεσιν</strong> (<em>kauchōmetha en tais thlipsesin</em>) — "we boast in our sufferings" — the same verb (<em>kauchaomai</em>) used for the boasting that faith excludes (3:27); now Paul redirects it toward sufferings. <em>Thlipsis</em> (pressure, affliction, tribulation) — from <em>thlibō</em> (to press, squeeze); concrete physical-social suffering, not merely inconvenience. <strong>εἰδότες ὅτι</strong> (<em>eidotes hoti</em>) — "knowing that" — the boasting is knowledge-based, not masochistic; the chain that follows (suffering → endurance → character → hope) is the rationale.</p>',
    "4": '<p><strong>ἡ δὲ ὑπομονὴ δοκιμήν</strong> (<em>hē de hypomonē dokimēn</em>) — "and endurance produces character" — <em>hypomonē</em> (endurance, remaining-under) and <em>dokimē</em> (tested character, that which has passed the test). The metallurgical testing image: the pressured metal that passes the test becomes certified as genuine. Suffering → tested endurance → certified character is the logic.</p>',
    "5": '<p><strong>οὐ καταισχύνει</strong> (<em>ou kataischynei</em>) — "does not put to shame/disappoint" — present active: the hope is continuously non-disappointing. The Roman context makes this pointed: hope in crucified criminals typically did put one to shame. Paul\'s claim is that this particular hope is vindicated by the Spirit\'s testimony. <strong>ἐκκέχυται</strong> (<em>ekkechytai</em>) — "has been poured out" — perfect passive: the divine love was poured and remains poured, a completed and abiding reality rather than a past event now concluded.</p>',
    "6": '<p><strong>ἔτι γὰρ Χριστὸς ὄντων ἡμῶν ἀσθενῶν κατὰ καιρὸν ὑπὲρ ἀσεβῶν ἀπέθανεν</strong> — "for while we were still weak, at the right time Christ died for the ungodly." <em>Kata kairon</em> (at the right moment, the appointed time) — <em>kairos</em> is qualitative time (significant moment) rather than chronological time (<em>chronos</em>); the timing of Christ\'s death is providentially exact. <em>Asebōn</em> (for the ungodly) — the same word as 4:5; Christ died for exactly those whom God justifies.</p>',
    "7": '<p><strong>μόλις γὰρ ὑπὲρ δικαίου τις ἀποθανεῖται</strong> — "for one would scarcely die for a righteous person" — the moral gradient Paul establishes: hardly anyone dies for the righteous (<em>dikaios</em>); perhaps someone dares to die for the genuinely good (<em>agathos</em>). The distinction between the merely-law-keeping righteous and the lovable-good represents the upper limit of human self-sacrifice.</p>',
    "8": '<p><strong>συνίστησιν δὲ τὴν ἑαυτοῦ ἀγάπην εἰς ἡμᾶς ὁ θεός</strong> (<em>synistēsin de tēn heautou agapēn eis hēmas ho theos</em>) — "but God demonstrates his own love toward us." <em>Synistēmi</em> (to establish, demonstrate, commend, prove) — more than display; the cross is a proof, an argument, a demonstration of the character of divine love. The emphasis on "his own" (<em>heautou</em>) and "toward us" (<em>eis hēmas</em>) makes the love personal and directed.</p>',
    "9": '<p><strong>πολλῷ οὖν μᾶλλον</strong> (<em>pollō oun mallon</em>) — "much more therefore" — the a-fortiori argument Paul will use repeatedly in vv9-11: if X (the greater) has been accomplished, how much more certainly Y (the lesser) will follow. Justification by Christ\'s blood is the greater (costly, accomplished while we were sinners); salvation from wrath is the lesser (what follows from the accomplished justification).</p>',
    "10": '<p><strong>εἰ γὰρ ἐχθροὶ ὄντες κατηλλάγημεν τῷ θεῷ</strong> (<em>ei gar echthroi ontes katēllagēmen tō theō</em>) — "for if while being enemies we were reconciled to God." <em>Echthroi ontes</em> — present participle: enemies as a present active state. <em>Katēllagēmen</em> — aorist passive: the reconciliation was accomplished from God\'s side, not worked up from ours. The a-fortiori: if reconciliation happened while we were enemies, how much more will salvation be certain now that we are friends. <strong>διὰ τοῦ θανάτου τοῦ υἱοῦ αὐτοῦ</strong> — "through the death of his Son" — reconciliation grounds in the most extreme possible divine act.</p>',
    "11": '<p><strong>καυχώμενοι ἐν τῷ θεῷ</strong> (<em>kauchōmenoi en tō theō</em>) — "boasting in God" — the third boasting in the chapter (v2: in hope; v3: in sufferings; now in God himself). The movement is: from circumstances → to suffering → to the God who is the ground of all three. <em>Katallagē</em> (reconciliation) — from <em>allassō</em> (to exchange); reconciliation as exchange: God takes our enmity and gives his friendship. The exchange theology Paul is building toward (5:12-21) begins here.</p>',
    "12": '<p><strong>δι᾽ ἑνὸς ἀνθρώπου ἡ ἁμαρτία εἰς τὸν κόσμον εἰσῆλθεν</strong> — "through one man sin entered the world." The historical singular act: Adam\'s disobedience as the point of entry. <strong>ἐφ᾽ ᾧ πάντες ἥμαρτον</strong> (<em>eph\' hō pantes hēmarton</em>) — the most debated phrase in the passage. <em>Eph\' hō</em> can mean (a) "because of whom" (relative pronoun — in whom = in Adam all sinned, Augustinian reading), (b) "in that" or "because" (conjunction — because all individually sinned, Eastern reading). The causal reading is grammatically more natural in Koine Greek; Paul probably means "because all individually sinned" while also holding the Adamic solidarity of vv15-21.</p>',
    "13": '<p><strong>ἄχρι γὰρ νόμου ἁμαρτία ἦν ἐν κόσμῳ</strong> (<em>achri gar nomou hamartia ēn en kosmō</em>) — "for until the law sin was in the world." Paul distinguishes sin (<em>hamartia</em>, the reality) from transgression (<em>parabasis</em>, knowing violation of a known command): sin existed between Adam and Moses but could not be formally charged as <em>parabasis</em> without a codified law.</p>',
    "14": '<p><strong>τύπος τοῦ μέλλοντος</strong> (<em>typos tou mellontos</em>) — "a type/pattern of the one to come." <em>Typos</em> (stamp, impression, figure) — the word from which "typology" derives; Adam is the structural pattern whose negative is filled positively by Christ. The type/antitype relationship is explicit here: Adam\'s one-act-of-disobedience-with-universal-consequence finds its counter in Christ\'s one-act-of-obedience-with-universal-consequence (v18-19).</p>',
    "15": '<p><strong>οὐχ ὡς τὸ παράπτωμα, οὕτως καὶ τὸ χάρισμα</strong> (<em>ouch hōs to paraptōma, houtōs kai to charisma</em>) — "but the gift is not like the trespass." <em>Paraptōma</em> (a falling-beside, trespass, deviation) and <em>charisma</em> (grace-gift). The dissimilarity Paul will emphasize: the trespass and the gift operate by different logic — one produces death through one; the other overflows life through many. The <em>pollō mallon</em> (much more) again: if the trespass accomplished much damage, the grace accomplishes overwhelmingly more.</p>',
    "16": '<p><strong>κρίμα μὲν γὰρ ἐξ ἑνὸς εἰς κατάκριμα, τὸ δὲ χάρισμα ἐκ πολλῶν παραπτωμάτων εἰς δικαίωμα</strong> — "judgment from one sin brought condemnation, but the gift from many trespasses brought justification." The asymmetry: the condemnation came from one trespass; the justification covers many trespasses. <em>Katakrima</em> (condemnation, the sentence itself) versus <em>dikaiōma</em> (justification, righteous decree/act). Grace absorbs what law multiplies.</p>',
    "17": '<p><strong>ἐν ζωῇ βασιλεύσουσιν</strong> (<em>en zōē basileusousin</em>) — "they will reign in life" — the eschatological reversal of Adam\'s condition: not merely restored to pre-fall status but elevated to reigning. The future tense (<em>basileusousin</em>) is both already-realized (in the Spirit\'s firstfruits) and still-anticipated (at the resurrection). Those who receive the abundance of grace become kings where Adam became a slave to death.</p>',
    "18": '<p><strong>δι᾽ ἑνὸς δικαιώματος</strong> (<em>di\' henos dikaiōmatos</em>) — "through one righteous act" — <em>dikaiōma</em> here means the single act of obedience (Christ\'s death as fulfillment of righteousness) rather than the legal verdict. The parallel with v16\'s "one trespass" is exact. <strong>εἰς δικαίωσιν ζωῆς</strong> — "resulting in justification of life" — the genitive <em>zōēs</em> (life) describes the character of the justification: it is a justification that produces life rather than merely legal standing.</p>',
    "19": '<p><strong>διὰ τῆς ὑπακοῆς τοῦ ἑνός</strong> (<em>dia tēs hypakoēs tou henos</em>) — "through the obedience of the one." The contrast with "the one man\'s disobedience" is exact. <em>Hypakoē</em> (obedience, literally: hearing-under) — the obedient life of Christ including but not limited to his death. <strong>κατασταθήσονται δίκαιοι</strong> (<em>katastathēsontai dikaioi</em>) — "will be constituted righteous" — future passive; the eschatological establishment of righteousness in the many, not merely its forensic declaration.</p>',
    "20": '<p><strong>νόμος δὲ παρεισῆλθεν</strong> (<em>nomos de pareisēlthen</em>) — "the law came in alongside" — <em>pareiserchomai</em> (to come in beside, slip in alongside) — the verb suggests the law\'s role as secondary, not primary: it entered the scene that had already been established by Adam\'s sin and the promise to Abraham. <strong>ἵνα πλεονάσῃ τὸ παράπτωμα</strong> — "so that the trespass might increase" — the purpose clause is deliberately provocative: the law\'s purpose includes the multiplication of trespass (clarifying, specifying, and thus increasing the catalog of violations). But: <strong>οὗ δὲ ἐπλεόνασεν ἡ ἁμαρτία, ὑπερεπερίσσευσεν ἡ χάρις</strong> — "where sin increased, grace superabounded." <em>Hyperperisseuō</em> (to overflow beyond all measure) — the <em>hyper-</em> prefix intensifies the already-intense <em>perisseuō</em>; grace exceeds sin by a qualitative order of magnitude, not merely a quantitative surplus.</p>',
    "21": '<p><strong>βασιλεύσῃ ἡ χάρις διὰ δικαιοσύνης εἰς ζωὴν αἰώνιον</strong> (<em>basileusē hē charis dia dikaiosynēs eis zōēn aiōnion</em>) — "grace might reign through righteousness unto eternal life." Grace is personified as the royal power that replaces sin\'s reign (v21a); its instrument is righteousness and its destination is eternal life. The political metaphor (reign, kingship) that has governed vv12-21 reaches its conclusion: the governance of reality has changed sovereigns through Jesus Christ.</p>'
  },
  "6": {
    "1": '<p><strong>ἐπιμένωμεν τῇ ἁμαρτίᾳ ἵνα ἡ χάρις πλεονάσῃ</strong> (<em>epimenōmen tē hamartia hina hē charis pleonasē</em>) — "shall we continue in sin so that grace may increase?" The logical inference from 5:20 stated as the objection Paul anticipated. <em>Epimenō</em> (to remain upon, persist in) — the deliberate, continued choice to remain in sin, not accidental failure. The <em>mē genoito</em> (certainly not!) that follows does not argue against the inference; it demonstrates the absurdity of what the inference requires one to overlook.</p>',
    "2": '<p><strong>οἵτινες ἀπεθάνομεν τῇ ἁμαρτίᾳ</strong> (<em>hoitines apethanomen tē hamartia</em>) — "we who died to sin" — aorist active: a completed death. The relative clause <em>hoitines</em> (we who are such people that) identifies the believers by this death-event. <strong>πῶς ἔτι ζήσομεν ἐν αὐτῇ</strong> — "how shall we still live in it?" — the rhetorical question points to the ontological impossibility: the dead person cannot continue in the life they died out of.</p>',
    "3": '<p><strong>ἐβαπτίσθημεν εἰς Χριστὸν Ἰησοῦν</strong> (<em>ebaptisthēmen eis Christon Iēsoun</em>) — "were baptized into Christ Jesus" — the <em>eis</em> (into) is significant: baptism is the act of going-into-Christ, of union with his person. <strong>εἰς τὸν θάνατον αὐτοῦ ἐβαπτίσθημεν</strong> — "baptized into his death" — the union is specifically with the death-event; baptism does not merely commemorate Christ\'s death but unites the baptized person with it.</p>',
    "4": '<p><strong>συνετάφημεν οὖν αὐτῷ διὰ τοῦ βαπτίσματος</strong> (<em>synetaphēmen oun autō dia tou baptismatos</em>) — "we were buried therefore with him through baptism" — <em>syntaptō</em> (to bury together with) — a compound verb of solidarity: not just that Christ was buried but that we were buried with him. <strong>ἐν καινότητι ζωῆς</strong> (<em>en kainotēti zōēs</em>) — "in newness of life" — <em>kainotēs</em> (newness in kind, qualitative novelty) as opposed to <em>neos</em> (new in age/time); the resurrection life is not the old life renewed but an ontologically new mode of existence.</p>',
    "5": '<p><strong>σύμφυτοι γεγόναμεν τῷ ὁμοιώματι τοῦ θανάτου αὐτοῦ</strong> (<em>symphytoi gegonamen tō homoiōmati tou thanatou autou</em>) — "we have been united with the likeness of his death." <em>Symphytos</em> (grown-together-with, organically joined) — a horticultural term (cf. grafting): the believer is not merely alongside Christ\'s death as a moral example but organically united to it. The perfect <em>gegonamen</em> (we have become and remain) indicates permanent organic union.</p>',
    "6": '<p><strong>ὁ παλαιὸς ἡμῶν ἄνθρωπος συνεσταυρώθη</strong> (<em>ho palaios hēmōn anthrōpos synestaurōthē</em>) — "our old man was crucified together with him" — <em>palaios anthrōpos</em> (old humanity) — not the body but the previous Adam-shaped mode of existence. <em>Systauroō</em> (to crucify together with) — the compound form of crucifixion: co-crucifixion, union in the death event. <strong>ἵνα καταργηθῇ τὸ σῶμα τῆς ἁμαρτίας</strong> — "so that the body of sin might be rendered inoperative" — <em>katargeō</em> again: not destroyed but rendered powerless, inactivated.</p>',
    "7": '<p><strong>ὁ γὰρ ἀποθανὼν δεδικαίωται ἀπὸ τῆς ἁμαρτίας</strong> (<em>ho gar apothanōn dedikaiōtai apo tēs hamartias</em>) — "for the one who has died has been justified from sin." The perfect passive <em>dedikaiōtai</em>: has been and remains acquitted from sin\'s claims. Death severs all legal claims; the dead person owes no further obligations to the old master. This principle Paul applies: the believer who has died with Christ is no longer subject to sin\'s legal authority.</p>',
    "8": '<p><strong>πιστεύομεν ὅτι καὶ συζήσομεν αὐτῷ</strong> (<em>pisteuomen hoti kai syzēsomen autō</em>) — "we believe that we will also live together with him." The future tense <em>syzēsomen</em> (we will co-live) points to the future resurrection as the completion of the union initiated in baptism; but the present tense <em>pisteuomen</em> (we are believing) grounds the future hope in present faith rather than future achievement.</p>',
    "9": '<p><strong>Χριστὸς ἐγερθεὶς ἐκ νεκρῶν οὐκέτι ἀποθνῄσκει</strong> — "Christ, having been raised from the dead, no longer dies." <em>Egertheisidēs</em> (aorist passive participle: having been raised) describes the historical event; <em>apothnēskei</em> (present tense: dies) the ongoing state — he no longer dies. <strong>θάνατος αὐτοῦ οὐκέτι κυριεύει</strong> — "death no longer lords it over him" — <em>kyrieuō</em> (to be lord, to exercise dominion) — the resurrection terminates death\'s lordship over Christ. Believers who are united with the risen Christ share in this freedom from death\'s dominion.</p>',
    "10": '<p><strong>ὃ γὰρ ἀπέθανεν, τῇ ἁμαρτίᾳ ἀπέθανεν ἐφάπαξ</strong> (<em>ho gar apethanen, tē hamartia apethanen ephapax</em>) — "for the death he died, he died to sin once for all." <em>Ephapax</em> (once for all, once for all time) — a term Paul uses only here and in Hebrews-related contexts; the finality and completeness of Christ\'s single death excludes repetition. <strong>ὃ δὲ ζῇ, ζῇ τῷ θεῷ</strong> — "but the life he lives, he lives to God" — the present tenses indicate the permanent quality of the resurrection life: it belongs entirely to God.</p>',
    "11": '<p><strong>λογίζεσθε ἑαυτοὺς νεκροὺς μὲν τῇ ἁμαρτίᾳ ζῶντας δὲ τῷ θεῷ</strong> (<em>logizesthe heautous nekrous men tē hamartia zōntas de tō theō</em>) — "reckon yourselves dead to sin but alive to God." <em>Logizesthe</em> (present active imperative: keep reckoning, continue counting) — the same forensic-accounting verb from ch4, now an ethical command. The command is not to make something true by effort but to count as true what is already true in Christ; the reckoning is the believing reception of the accomplished reality.</p>',
    "12": '<p><strong>μὴ οὖν βασιλευέτω ἡ ἁμαρτία ἐν τῷ θνητῷ ὑμῶν σώματι</strong> (<em>mē oun basileuetō hē hamartia en tō thnētō hymōn sōmati</em>) — "let not sin therefore reign in your mortal body." The present imperative with <em>mē</em> can mean: stop what is in progress, or maintain the prevention of what might begin. <em>Thnētō sōmati</em> (mortal body) — sin\'s domain is the body subject to death; the body is not evil but is the site where sin seeks to re-establish its reign after it has been deposed in principle.</p>',
    "13": '<p><strong>παραστάνετε ἑαυτοὺς τῷ θεῷ</strong> (<em>parastanete heautous tō theō</em>) — "present yourselves to God" — <em>paristēmi</em> (to place beside, present) has a cultic resonance: the priestly presentation of the offering. The believer presents themselves as living offerings (cf. 12:1). <strong>ὡσεὶ ἐκ νεκρῶν ζῶντας</strong> — "as those who are alive from the dead" — the ethical imperative is grounded in the indicative status: present yourselves as what you actually are — the risen-from-the-dead.</p>',
    "14": '<p><strong>ἁμαρτία γὰρ ὑμῶν οὐ κυριεύσει</strong> (<em>hamartia gar hymōn ou kyrieusei</em>) — "for sin will not be lord over you" — future active: a categorical promise, not merely an aspiration. <strong>οὐ γάρ ἐστε ὑπὸ νόμον ἀλλ᾽ ὑπὸ χάριν</strong> — "for you are not under law but under grace" — the preposition <em>hypo</em> (under) indicates dominion: "under law" = subject to law\'s jurisdiction and condemnation; "under grace" = in grace\'s domain where sin has been dethroned.</p>',
    "15": '<p><strong>τί οὖν; ἁμαρτήσωμεν ὅτι οὐκ ἐσμὲν ὑπὸ νόμον ἀλλ᾽ ὑπὸ χάριν</strong> — the second objection to Paul\'s grace-teaching; structurally parallel to 6:1 but from a different angle. v1 raised the possibility of continuing in sin under grace; v15 raises the possibility of sinning once because under grace rather than law. The <em>mē genoito</em> dismisses both with equal finality.</p>',
    "16": '<p><strong>ᾧ παριστάνετε ἑαυτοὺς δούλους εἰς ὑπακοήν</strong> — "to whom you present yourselves as slaves for obedience" — the slave-obedience framework: one always serves someone; freedom from sin is not freedom from all masters but transfer to a new master. <strong>ἤτοι ἁμαρτίας εἰς θάνατον ἢ ὑπακοῆς εἰς δικαιοσύνην</strong> — "either of sin leading to death or of obedience leading to righteousness" — the binary is unavoidable: one\'s obedience determines one\'s destiny-direction.</p>',
    "17": '<p><strong>ὑπηκούσατε δὲ ἐκ καρδίας εἰς ὃν παρεδόθητε τύπον διδαχῆς</strong> (<em>hypēkousate de ek kardias eis hon paredothēte typon didachēs</em>) — "you obeyed from the heart the pattern of teaching to which you were handed over." Note the passive: the believers were delivered to the teaching, not just taught it; the teaching takes possession of its recipients. <em>Ek kardias</em> (from the heart) — the obedience is interior and voluntary, not merely behavioral compliance.</p>',
    "18": '<p><strong>ἐλευθερωθέντες δὲ ἀπὸ τῆς ἁμαρτίας ἐδουλώθητε τῇ δικαιοσύνῃ</strong> — "having been freed from sin, you became enslaved to righteousness." Both <em>ēleutherōthentes</em> (freed) and <em>edoulōthēte</em> (enslaved) are aorist passives: both are divine acts, both completed. Freedom from sin is not independence but transfer of ownership — enslaved to righteousness as the new master.</p>',
    "19": '<p><strong>ἀνθρώπινον λέγω διὰ τὴν ἀσθένειαν τῆς σαρκὸς ὑμῶν</strong> — "I am speaking in human terms because of the weakness of your flesh" — Paul acknowledges the inadequacy of the slave-metaphor while using it for pedagogical accessibility. The metaphor breaks down because Christian life under grace is both freedom and service simultaneously; the slave-image captures only the service dimension.</p>',
    "20": '<p><strong>ἐλεύθεροι ἦτε τῇ δικαιοσύνῃ</strong> (<em>eleutheroi ēte tē dikaiosynē</em>) — "you were free from righteousness" — the dative of reference: free with respect to righteousness, i.e., righteousness had no claim on you. The irony is sharp: slavery to sin was experienced as freedom; the "freedom" was in fact maximum bondage.</p>',
    "21": '<p><strong>τίνα οὖν καρπὸν εἴχετε τότε</strong> — "what fruit did you have then?" — the fruit metaphor measures the product of the old life: the <em>karpos</em> (fruit) of the sin-life is shame and death. The harvest of sin reveals its character; Paul invites the Romans to evaluate their pre-conversion life by its actual product.</p>',
    "22": '<p><strong>εἰς ἁγιασμόν</strong> (<em>eis hagiasmon</em>) — "resulting in sanctification" — <em>hagiasmos</em> (holiness, sanctification, the process of becoming holy) — different from <em>hagiasmos</em> as an instantaneous act; the word indicates the ongoing process of being consecrated to God. <strong>τέλος δὲ ζωὴν αἰώνιον</strong> — "and the end/goal is eternal life" — <em>telos</em> (end, completion, goal) — the harvest-metaphor reaches its eschatological conclusion: eternal life is both the end-of-the-process and the final harvest.</p>',
    "23": '<p><strong>τὰ γὰρ ὀψώνια τῆς ἁμαρτίας θάνατος</strong> (<em>ta gar opsōnia tēs hamartias thanatos</em>) — "for the wages of sin is death." <em>Opsōnion</em> (wage, ration, soldier\'s pay) — a military term for the wages due a soldier; sin pays its own workers exactly what it owes them. <strong>τὸ δὲ χάρισμα τοῦ θεοῦ ζωὴ αἰώνιος ἐν Χριστῷ Ἰησοῦ τῷ κυρίῳ ἡμῶν</strong> — "but the gift of God is eternal life in Christ Jesus our Lord" — <em>charisma</em> (grace-gift) deliberately contrasted with <em>opsōnion</em> (earned wages): life is not a wage but a gift, not earned but given.</p>'
  },
  "7": {
    "1": '<p><strong>κυριεύει τοῦ ἀνθρώπου</strong> (<em>kyrieuei tou anthrōpou</em>) — "lords it over a person" — <em>kyrieuō</em> (exercise lordship over) with the genitive: the law\'s dominion is the legal claim it has over the living. The principle Paul will illustrate with the marriage analogy: death terminates legal obligation.</p>',
    "2": '<p><strong>τῷ ζῶντι ἀνδρὶ δέδεται νόμῳ</strong> (<em>tō zōnti andri dedetai nomō</em>) — "she is bound by law to the living husband" — <em>dedetai</em> (perfect passive: has been bound and remains bound) — marriage as a permanent legal obligation while both parties live. <strong>ἐὰν δὲ ἀποθάνῃ ὁ ἀνήρ</strong> — "but if the husband dies" — death is the one event that dissolves the legal bond; Paul\'s analogy requires that the believer die (with Christ) to be freed from the law\'s claim.</p>',
    "3": '<p><strong>ἐλευθέρα ἐστὶν ἀπὸ τοῦ νόμου</strong> (<em>eleuthera estin apo tou nomou</em>) — "she is free from the law" — the marriage analogy establishes the principle: death releases from legal obligation. The wife who remarries while her husband lives is a <em>moichalis</em> (adulteress); but if he has died, the same action is lawful. Paul will apply this: the believer died with Christ and is therefore free to "marry" (be united with) the risen Christ without violating the law.</p>',
    "4": '<p><strong>ὥστε, ἀδελφοί μου, καὶ ὑμεῖς ἐθανατώθητε τῷ νόμῳ διὰ τοῦ σώματος τοῦ Χριστοῦ</strong> — "so then, my brothers and sisters, you also were put to death with regard to the law through the body of Christ." Note the asymmetry with the analogy: in the analogy the husband dies; in the application the wife (believer) dies. Paul\'s application inverts the subject of death because believers are united with Christ who died; they die through his body, not he through theirs. <strong>εἰς τὸ γενέσθαι ὑμᾶς ἑτέρῳ</strong> — "so that you might belong to another" — the purpose clause: death-with-Christ enables new belonging to the risen Christ; the new husband is the resurrection life.</p>',
    "5": '<p><strong>ἐν τῇ σαρκί</strong> (<em>en tē sarki</em>) — "in the flesh" — not the physical body per se but the mode of existence characterized by the Adamic nature. The flesh-era is the pre-Christ condition; the Spirit-era is the new-creation condition. <strong>τὰ παθήματα τῶν ἁμαρτιῶν τὰ διὰ τοῦ νόμου</strong> — "the passions of sins through the law" — the law\'s role in arousing the very sins it prohibits is Paul\'s theme; the <em>dia tou nomou</em> (through the law) is the disturbing claim that the holy law is the mechanism through which sinful passions operate.</p>',
    "6": '<p><strong>κατηργήθημεν ἀπὸ τοῦ νόμου</strong> (<em>katērgēthēmen apo tou nomou</em>) — "we have been released from the law" — <em>katargeō</em> again: the law has been rendered inoperative in its claim on those who have died with Christ. <strong>ἐν καινότητι πνεύματος καὶ οὐ παλαιότητι γράμματος</strong> (<em>en kainotēti pneumatos kai ou palaiōtēti grammatos</em>) — "in newness of Spirit and not in oldness of letter." The <em>pneuma/gramma</em> antithesis (Spirit/letter) is the Pauline expression for the new-covenant/old-covenant distinction; the letter kills (because it condemns without empowering), the Spirit gives life (2 Cor 3:6).</p>',
    "7": '<p><strong>τί οὖν ἐροῦμεν; ὁ νόμος ἁμαρτία</strong> (<em>ti oun eroumen; ho nomos hamartia</em>) — "what then shall we say? Is the law sin?" The implication of v5-6 (sin works through the law): is the law itself sinful? Paul\'s <em>mē genoito</em> is emphatic. <strong>τὴν ἁμαρτίαν οὐκ ἔγνων εἰ μὴ διὰ νόμου</strong> — "I would not have known sin except through the law" — the law\'s diagnostic function: it reveals what sin is by naming it. <strong>τὴν ἐπιθυμίαν οὐκ ᾔδειν</strong> — "I would not have known covetousness" — the last commandment of the Decalogue (οὐκ ἐπιθυμήσεις) is the example Paul chooses — perhaps because it addresses the interior desire rather than the external act, making it the commandment that most clearly exposes the depth of sin.</p>',
    "8": '<p><strong>ἀφορμὴν δὲ λαβοῦσα ἡ ἁμαρτία</strong> (<em>aphormēn de labousa hē hamartia</em>) — "but sin, seizing an opportunity" — <em>aphormē</em> (base of operations, starting point for a military expedition); sin uses the commandment as its beachhead. <strong>κατειργάσατο ἐν ἐμοὶ πᾶσαν ἐπιθυμίαν</strong> — "produced in me all kinds of covetousness" — the commandment\'s naming of the forbidden desire becomes the stimulus that sin exploits to produce more of the very thing forbidden.</p>',
    "9": '<p><strong>ἐγὼ δὲ ἔζων χωρὶς νόμου ποτέ</strong> (<em>egō de ezōn chōris nomou pote</em>) — "I was once alive apart from the law" — the autobiographical/representative <em>egō</em> describes a pre-commandment state of living. This may be: (a) Paul\'s own pre-Torah-consciousness childhood; (b) Adam before the commandment; (c) generic Israel before Sinai. All three levels are probably operative. <strong>ἐλθούσης δὲ τῆς ἐντολῆς ἡ ἁμαρτία ἀνέζησεν</strong> — "but when the commandment came, sin came to life" — aorist: sin\'s revival is an event triggered by the commandment\'s arrival.</p>',
    "10": '<p><strong>καὶ εὑρέθη μοι ἡ ἐντολὴ ἡ εἰς ζωήν, αὕτη εἰς θάνατον</strong> — "and the commandment that was intended for life proved to be death for me." The divine intention of the law (<em>eis zōēn</em> = for life, referencing Lev 18:5) and its actual effect in the sin-condition (<em>eis thanaton</em> = for death) are both real; the law is not at fault but sin exploits it. The irony: what was given to produce life produces death because sin perverts it.</p>',
    "11": '<p><strong>ἡ γὰρ ἁμαρτία ἀφορμὴν λαβοῦσα διὰ τῆς ἐντολῆς ἐξηπάτησέν με</strong> (<em>hē gar hamartia aphormēn labousa dia tēs entolēs exēpatēsen me</em>) — "for sin, having seized an opportunity through the commandment, deceived me." <em>Exapataō</em> (to thoroughly deceive) — the Eve-parallel is explicit: as the serpent used the commandment (Gen 3:1-5) to deceive Eve, so sin uses the commandment to deceive the <em>egō</em>. The Genesis allusion is embedded in the verb.</p>',
    "12": '<p><strong>ὥστε ὁ μὲν νόμος ἅγιος καὶ ἡ ἐντολὴ ἁγία καὶ δικαία καὶ ἀγαθή</strong> — "so then the law is holy, and the commandment is holy and just and good." Three predicates clarifying the law\'s character after the argument that sin exploited it: <em>hagios</em> (consecrated, belonging to God\'s sphere), <em>dikaios</em> (right by God\'s standard), <em>agathos</em> (genuinely good in its nature). The law\'s perversion by sin does not impugn the law; the fault is sin\'s alone.</p>',
    "13": '<p><strong>ἀλλὰ ἡ ἁμαρτία, ἵνα φανῇ ἁμαρτία</strong> (<em>alla hē hamartia, hina phanē hamartia</em>) — "but sin, so that it might appear as sin." The purpose clause is divine: God allowed sin to work through the good commandment precisely so that sin would be fully exposed as sin — its true character revealed by its exploitation of holiness. <strong>ἵνα γένηται καθ᾽ ὑπερβολὴν ἁμαρτωλὸς ἡ ἁμαρτία</strong> — "so that sin might become utterly sinful through the commandment" — <em>kath\' hyperbolēn</em> (beyond measure, to the extreme) — sin becomes maximally sinful when it uses the holy commandment as its instrument.</p>',
    "14": '<p><strong>ὁ νόμος πνευματικός ἐστιν, ἐγὼ δὲ σάρκινός εἰμι, πεπραμένος ὑπὸ τὴν ἁμαρτίαν</strong> (<em>ho nomos pneumatikos estin, egō de sarkinos eimi, pepramenos hypo tēn hamartian</em>) — "the law is spiritual, but I am fleshly, sold under sin." The contrast <em>pneumatikos/sarkinos</em> (spiritual/fleshly) — the law belongs to God\'s sphere; the <em>egō</em> belongs to the flesh-sphere. <em>Pepramenos</em> (perfect passive participle: sold and remaining sold) — the slave who has been sold and cannot buy himself back. The famous identity of the <em>egō</em> (Christian? pre-Christian? rhetorical?) is unresolved; the present tense "I am" and "I want" in vv15-24 are the strongest evidence that Paul is describing a Christian condition under the ongoing pull of the Adamic nature.</p>',
    "15": '<p><strong>ὃ γὰρ κατεργάζομαι οὐ γινώσκω</strong> (<em>ho gar katergazomai ou ginōskō</em>) — "for I do not understand what I am doing" — not intellectual ignorance but the breakdown between intention and action that defines the divided self. <strong>οὐ γὰρ ὃ θέλω τοῦτο πράσσω, ἀλλ᾽ ὃ μισῶ τοῦτο ποιῶ</strong> — "for what I want, this I do not practice; but what I hate, this I do" — the two present-tense verbs of action (<em>prassō, poiō</em>) describe habitual patterns; the <em>thelō</em> (want/will) describes the consistent moral intention that nevertheless fails to translate into action.</p>',
    "16": '<p><strong>εἰ δὲ ὃ οὐ θέλω τοῦτο ποιῶ, σύμφημι τῷ νόμῳ ὅτι καλός</strong> — "but if I do what I do not want, I agree with the law that it is good." The <em>egō</em>\'s will (<em>thelō</em>) aligns with the law\'s standard even while actions fail to follow. This alignment of willing-with-law is itself evidence of the law\'s goodness and of the <em>egō</em>\'s genuine moral aspiration, however frustrated.</p>',
    "17": '<p><strong>νυνὶ δὲ οὐκέτι ἐγὼ κατεργάζομαι αὐτό</strong> (<em>nyni de ouketi egō katergazomai auto</em>) — "but now it is no longer I who am doing it." The <em>nyni de</em> introduces a crucial distinction: the <em>egō</em> (the true, willing, law-agreeing self) and <strong>ἡ οἰκοῦσα ἐν ἐμοὶ ἁμαρτία</strong> (<em>hē oikousa en emoi hamartia</em>) — "sin dwelling in me" — <em>oikeō</em> (to dwell, inhabit) as a present participle: sin occupies the <em>egō</em> as an invasive resident. The distinction between the <em>egō</em> and the indwelling sin anticipates the body-resurrection solution.</p>',
    "18": '<p><strong>οἶδα γὰρ ὅτι οὐκ οἰκεῖ ἐν ἐμοί, τοῦτ᾽ ἔστιν ἐν τῇ σαρκί μου, ἀγαθόν</strong> — "for I know that good does not dwell in me, that is, in my flesh." The qualification "that is, in my flesh" is crucial: the <em>egō</em> is not wholly bad; it is the <em>sarx</em> (flesh, the unredeemed bodily existence) in which good does not dwell. <strong>τὸ γὰρ θέλειν παράκειταί μοι, τὸ δὲ κατεργάζεσθαι τὸ καλὸν οὔ</strong> — "for wanting is present with me, but the doing of good is not" — the vocabulary of presence (<em>parakeimai</em>, to lie beside) contrasts the present-wanting with the absent-doing.</p>',
    "19": '<p><strong>οὐ γὰρ ὃ θέλω ποιῶ ἀγαθόν, ἀλλ᾽ ὃ οὐ θέλω κακὸν τοῦτο πράσσω</strong> — "for the good that I want, I do not do; but the evil I do not want, this I practice." The exact repetition of vv15-16 with the nouns <em>agathon</em> (good) and <em>kakon</em> (evil) specified. The rhetorical repetition is Paul\'s technique of drilling home the severity of the divided self before the resolution of ch8.</p>',
    "20": '<p><strong>εἰ δὲ ὃ οὐ θέλω ἐγὼ τοῦτο ποιῶ, οὐκέτι ἐγὼ κατεργάζομαι αὐτό</strong> — the same logic as v17 restated: if the <em>egō</em>\'s will is not the source of the unwanted action, the agent is the indwelling sin. The double <em>ouketi egō</em> (no longer I) in vv17 and 20 emphasizes the dissociation; yet this is not an evasion of responsibility but an analysis of the divided anthropology that requires the Spirit\'s liberation (ch8) for resolution.</p>',
    "21": '<p><strong>εὑρίσκω ἄρα τὸν νόμον</strong> (<em>heuriskō ara ton nomon</em>) — "so I find the law/principle" — <em>nomos</em> here probably means "principle" or "pattern" rather than the Mosaic Torah; the <em>egō</em> discovers a law-like inevitability in its condition: when it wants to do good, evil is present alongside. The discovery is experiential, not theoretical.</p>',
    "22": '<p><strong>συνήδομαι γὰρ τῷ νόμῳ τοῦ θεοῦ κατὰ τὸν ἔσω ἄνθρωπον</strong> (<em>synēdomai gar tō nomō tou theou kata ton esō anthrōpon</em>) — "for I delight in the law of God according to the inner person." <em>Synēdomai</em> (to rejoice together with, delight in) — a rare verb; the <em>egō</em>\'s delight in the law of God is genuine and deep. <em>Esō anthrōpos</em> (inner person) — the real self that the Spirit is renewing (2 Cor 4:16; Eph 3:16), in contrast to the flesh that resists the law.</p>',
    "23": '<p><strong>βλέπω δὲ ἕτερον νόμον ἐν τοῖς μέλεσίν μου ἀντιστρατευόμενον τῷ νόμῳ τοῦ νοός μου</strong> — "but I see another law in my members warring against the law of my mind." <em>Antistrateuomai</em> (to wage war against, counter-campaign) — the military metaphor for the conflict within the self: two laws, two armies, the same person as the battleground. <strong>αἰχμαλωτίζοντά με τῷ νόμῳ τῆς ἁμαρτίας</strong> — "taking me captive to the law of sin" — <em>aichmalōtizō</em> (to take as a prisoner of war); the divided self is the prisoner of the flesh-law even while the mind agrees with God\'s law.</p>',
    "24": '<p><strong>ταλαίπωρος ἐγὼ ἄνθρωπος· τίς με ῥύσεται ἐκ τοῦ σώματος τοῦ θανάτου τούτου</strong> (<em>talaipōros egō anthrōpos; tis me rhysetai ek tou sōmatos tou thanatou toutou</em>) — "Wretched man that I am! Who will rescue me from this body of death?" <em>Talaipōros</em> (wretched, exhausted from toil and conflict) — the most visceral emotional utterance in the letter. <em>Tis me rhysetai</em> (who will rescue me?) — the future tense: the rescue is still expected, not abandoned. <em>Sōma tou thanatou</em> (body of death) — the mortal body that is the site of sin\'s indwelling; rescue from this body = the bodily resurrection.</p>',
    "25": '<p><strong>χάρις δὲ τῷ θεῷ διὰ Ἰησοῦ Χριστοῦ τοῦ κυρίου ἡμῶν</strong> (<em>charis de tō theō dia Iēsou Christou tou kyriou hēmōn</em>) — "thanks be to God through Jesus Christ our Lord!" The sudden doxological answer: the rescue of v24 is already known; the thanksgiving anticipates the full exposition of ch8. <strong>Ἄρα οὖν αὐτὸς ἐγὼ τῷ μὲν νοῒ δουλεύω νόμῳ θεοῦ τῇ δὲ σαρκὶ νόμῳ ἁμαρτίας</strong> — "so then, I myself serve God\'s law with my mind but with my flesh I serve the law of sin." The summary restates the divided condition; the ch7 <em>egō</em> remains divided until the Spirit\'s liberation in ch8. Paul does not resolve the tension in ch7 but in ch8 — the dramatic movement of the letter.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'romans')
    merge_comm(existing, ROMANS)
    save_comm('mkt-original', 'romans', existing)
    print('Romans 4–7 mkt-original written.')

if __name__ == '__main__':
    main()
